void
print_token(const antlr4::Token* token,
            std::ofstream& outFile,
            const antlr4::Lexer& lexer)
{
  // Cast to our custom token type
  auto positionedToken = dynamic_cast<const SYsULexer::PositionedToken*>(token);
  if (!positionedToken) {
    // Fallback to default formatting
    outFile << token->toString() << std::endl;
    return;
  }

  // Get token name
  std::string tokenName;
  if (token->getType() == antlr4::Token::EOF) {
    tokenName = "eof";
  } else {
    tokenName = lexer.getVocabulary().getSymbolicName(token->getType());
    if (tokenName.empty()) {
      tokenName = std::to_string(token->getType());
    }
  }

  // Format token as required
  outFile << tokenName << " '" << token->getText() << "'";
  if (positionedToken->startOfLine) outFile << " [StartOfLine]";
  if (positionedToken->leadingSpace) outFile << " [LeadingSpace]";
  outFile << " Loc=<" << positionedToken->filename 
          << ":" << token->getLine() 
          << ":" << positionedToken->col << ">" << std::endl;
}

